const BASE = window.location.origin;
const root = htmlNode.querySelector('#sim-root') || htmlNode;
root.innerHTML = '';

const css = document.createElement('style');
css.textContent = `
  .sim-card { background: rgba(0,188,212,0.06); border: 1px solid rgba(0,188,212,0.25); border-radius: 10px; padding: 14px; margin-bottom: 10px; }
  .sim-card h4 { margin: 0 0 4px; font-size: 13px; color: #00e5ff; font-family: 'Orbitron', sans-serif; letter-spacing: 0.05em; }
  .sim-card p { margin: 0 0 8px; font-size: 11px; color: #888; }
  .sim-row { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; flex-wrap: wrap; }
  .sim-btn { background: #00bcd4; color: #000; border: none; border-radius: 6px; padding: 6px 14px; font-size: 11px; font-weight: 700; cursor: pointer; font-family: 'Share Tech Mono', monospace; }
  .sim-btn:hover { background: #00e5ff; }
  .sim-btn.red { background: #e53935; }
  .sim-btn.red:hover { background: #ff5252; }
  .sim-btn.amber { background: #ff9800; }
  .sim-btn.amber:hover { background: #ffb74d; }
  .sim-btn:disabled { opacity: 0.4; cursor: not-allowed; }
  .sim-slider { width: 120px; accent-color: #00bcd4; }
  .sim-label { font-size: 11px; color: #aaa; min-width: 80px; font-family: 'Share Tech Mono', monospace; }
  .sim-val { font-size: 11px; color: #00e5ff; min-width: 30px; text-align: right; font-family: 'Share Tech Mono', monospace; }
  .sim-log { background: #0a0a0a; border: 1px solid #222; border-radius: 8px; padding: 10px; margin-top: 10px; max-height: 260px; overflow-y: auto; font-size: 11px; font-family: 'Share Tech Mono', monospace; color: #ccc; }
  .sim-log .entry { padding: 3px 0; border-bottom: 1px solid #1a1a1a; }
  .sim-log .ts { color: #555; margin-right: 6px; }
  .sim-log .ok { color: #00e5ff; }
  .sim-log .err { color: #e53935; }
  .sim-log .warn { color: #ff9800; }
`;
root.appendChild(css);

const log = [];
function addLog(msg, cls) {
  const ts = new Date().toLocaleTimeString();
  log.unshift({ ts, msg, cls: cls || 'ok' });
  if (log.length > 50) log.length = 50;
  renderLog();
}
let logEl;
function renderLog() {
  if (!logEl) return;
  logEl.innerHTML = log.map(e => `<div class=\"entry\"><span class=\"ts\">${e.ts}</span><span class=\"${e.cls}\">${e.msg}</span></div>`).join('');
}

// ── Single Error ──
const c1 = document.createElement('div'); c1.className = 'sim-card';
c1.innerHTML = '<h4>TRIGGER ERROR</h4><p>Hit /test-error once to generate a 500 response</p>';
const b1 = document.createElement('button'); b1.className = 'sim-btn red'; b1.textContent = 'Fire 500';
b1.onclick = async () => {
  b1.disabled = true;
  try {
    const r = await fetch(BASE + '/test-error');
    addLog(`/test-error → ${r.status}`, r.status >= 500 ? 'err' : 'ok');
  } catch(e) { addLog(`Error: ${e.message}`, 'err'); }
  b1.disabled = false;
};
c1.appendChild(b1);
root.appendChild(c1);

// ── Error Burst ──
const c2 = document.createElement('div'); c2.className = 'sim-card';
c2.innerHTML = '<h4>ERROR BURST</h4><p>Fire N requests to /test-error to spike the error rate metric</p>';
const r2 = document.createElement('div'); r2.className = 'sim-row';
let burstCount = 20;
r2.innerHTML = `<span class=\"sim-label\">Count</span><input type=\"range\" class=\"sim-slider\" min=\"5\" max=\"200\" value=\"20\"><span class=\"sim-val\">20</span>`;
const sl2 = r2.querySelector('input');
const sv2 = r2.querySelector('.sim-val');
sl2.oninput = () => { burstCount = +sl2.value; sv2.textContent = sl2.value; };
c2.appendChild(r2);
const b2 = document.createElement('button'); b2.className = 'sim-btn red'; b2.textContent = 'Fire Burst';
b2.onclick = async () => {
  b2.disabled = true; b2.textContent = 'Firing...';
  let ok = 0, fail = 0;
  for (let i = 0; i < burstCount; i += 10) {
    const batch = Math.min(10, burstCount - i);
    const ps = Array.from({length: batch}, () => fetch(BASE + '/test-error').then(r => r.status).catch(() => 0));
    const res = await Promise.all(ps);
    res.forEach(s => s >= 500 ? fail++ : ok++);
  }
  addLog(`Burst: ${fail} errors / ${fail+ok} total`, fail > 0 ? 'err' : 'ok');
  b2.disabled = false; b2.textContent = 'Fire Burst';
};
c2.appendChild(b2);
root.appendChild(c2);

// ── Traffic Spike ──
const c3 = document.createElement('div'); c3.className = 'sim-card';
c3.innerHTML = '<h4>TRAFFIC SPIKE</h4><p>Instant burst of concurrent GET /health requests</p>';
const r3 = document.createElement('div'); r3.className = 'sim-row';
let spikeCount = 50;
r3.innerHTML = `<span class=\"sim-label\">Requests</span><input type=\"range\" class=\"sim-slider\" min=\"10\" max=\"500\" value=\"50\"><span class=\"sim-val\">50</span>`;
const sl3 = r3.querySelector('input');
const sv3 = r3.querySelector('.sim-val');
sl3.oninput = () => { spikeCount = +sl3.value; sv3.textContent = sl3.value; };
c3.appendChild(r3);
const b3 = document.createElement('button'); b3.className = 'sim-btn amber'; b3.textContent = 'Spike';
b3.onclick = async () => {
  b3.disabled = true; b3.textContent = 'Spiking...';
  const t0 = Date.now();
  const ps = Array.from({length: spikeCount}, () => fetch(BASE + '/health').then(r => r.status).catch(() => 0));
  const res = await Promise.all(ps);
  const ms = Date.now() - t0;
  const ok = res.filter(s => s === 200).length;
  addLog(`Spike: ${ok}/${res.length} ok in ${ms}ms (${(res.length/(ms/1000)).toFixed(0)} rps)`, 'ok');
  b3.disabled = false; b3.textContent = 'Spike';
};
c3.appendChild(b3);
root.appendChild(c3);

// ── Concurrent Users ──
const c4 = document.createElement('div'); c4.className = 'sim-card';
c4.innerHTML = '<h4>CONCURRENT USERS</h4><p>Simulate N users hitting random endpoints for a set duration</p>';
const r4a = document.createElement('div'); r4a.className = 'sim-row';
let userCount = 10;
r4a.innerHTML = `<span class=\"sim-label\">Users</span><input type=\"range\" class=\"sim-slider\" min=\"1\" max=\"200\" value=\"10\"><span class=\"sim-val\">10</span>`;
const sl4a = r4a.querySelector('input');
const sv4a = r4a.querySelector('.sim-val');
sl4a.oninput = () => { userCount = +sl4a.value; sv4a.textContent = sl4a.value; };
c4.appendChild(r4a);
const r4b = document.createElement('div'); r4b.className = 'sim-row';
let durSec = 5;
r4b.innerHTML = `<span class=\"sim-label\">Duration (s)</span><input type=\"range\" class=\"sim-slider\" min=\"1\" max=\"30\" value=\"5\"><span class=\"sim-val\">5</span>`;
const sl4b = r4b.querySelector('input');
const sv4b = r4b.querySelector('.sim-val');
sl4b.oninput = () => { durSec = +sl4b.value; sv4b.textContent = sl4b.value; };
c4.appendChild(r4b);
const b4 = document.createElement('button'); b4.className = 'sim-btn'; b4.textContent = 'Start Load';
b4.onclick = async () => {
  b4.disabled = true; b4.textContent = `Running ${durSec}s...`;
  const endpoints = ['/health', '/users?per_page=5', '/urls?per_page=5', '/events?per_page=5'];
  const end = Date.now() + durSec * 1000;
  let total = 0, errs = 0;
  const lats = [];
  const work = Array.from({length: userCount}, async () => {
    while (Date.now() < end) {
      const ep = endpoints[Math.floor(Math.random() * endpoints.length)];
      const t0 = Date.now();
      try {
        const r = await fetch(BASE + ep);
        lats.push(Date.now() - t0);
        total++;
        if (r.status >= 500) errs++;
      } catch { errs++; total++; }
    }
  });
  await Promise.all(work);
  lats.sort((a,b) => a - b);
  const p50 = lats[Math.floor(lats.length * 0.5)] || 0;
  const p95 = lats[Math.floor(lats.length * 0.95)] || 0;
  const rps = (total / durSec).toFixed(0);
  const errPct = total ? ((errs/total)*100).toFixed(1) : '0';
  addLog(`Load: ${userCount} users, ${total} reqs, ${rps} rps, p50=${p50}ms p95=${p95}ms, err=${errPct}%`, errs > 0 ? 'warn' : 'ok');
  b4.disabled = false; b4.textContent = 'Start Load';
};
c4.appendChild(b4);
root.appendChild(c4);

// ── Fire Alert ──
const c5 = document.createElement('div'); c5.className = 'sim-card';
c5.innerHTML = '<h4>FIRE ALERT</h4><p>Create an alert record in the Flask app database</p>';
const r5 = document.createElement('div'); r5.className = 'sim-row';
r5.innerHTML = `<input placeholder=\"Alert name\" style=\"background:#111;border:1px solid #333;color:#eee;padding:4px 8px;border-radius:4px;font-size:11px;width:140px;font-family:'Share Tech Mono',monospace\" id=\"sim-alert-name\"><select style=\"background:#111;border:1px solid #333;color:#eee;padding:4px 8px;border-radius:4px;font-size:11px;font-family:'Share Tech Mono',monospace\" id=\"sim-alert-sev\"><option value=\"warning\">warning</option><option value=\"critical\">critical</option></select><input placeholder=\"Summary (optional)\" style=\"background:#111;border:1px solid #333;color:#eee;padding:4px 8px;border-radius:4px;font-size:11px;width:200px;font-family:'Share Tech Mono',monospace\" id=\"sim-alert-sum\">`;
c5.appendChild(r5);
const b5 = document.createElement('button'); b5.className = 'sim-btn red'; b5.textContent = 'Fire Alert';
b5.onclick = async () => {
  const name = root.querySelector('#sim-alert-name').value.trim();
  if (!name) { addLog('Alert name required', 'err'); return; }
  const sev = root.querySelector('#sim-alert-sev').value;
  const sum = root.querySelector('#sim-alert-sum').value.trim();
  b5.disabled = true;
  try {
    const r = await fetch(BASE + '/alerts', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ alert_name: name, severity: sev, summary: sum || undefined, source: 'grafana-simulate' })
    });
    const d = await r.json();
    addLog(`Alert fired: ${name} (${sev}) → id=${d.id}`, 'ok');
    root.querySelector('#sim-alert-name').value = '';
    root.querySelector('#sim-alert-sum').value = '';
  } catch(e) { addLog(`Alert error: ${e.message}`, 'err'); }
  b5.disabled = false;
};
c5.appendChild(b5);
root.appendChild(c5);

// ── Log ──
logEl = document.createElement('div'); logEl.className = 'sim-log';
logEl.innerHTML = '<div class=\"entry\"><span class=\"ts\">' + new Date().toLocaleTimeString() + '</span><span class=\"ok\">Simulation panel ready</span></div>';
root.appendChild(logEl);
